/**
 * Builder for {@link AsyncExtendClient} - not auto-generated by Fern.
 *
 * <p>Fern generates {@link AsyncExtendClientBaseBuilder}; this hand-written builder keeps the
 * historical {@code AsyncExtendClientBuilder} type name and overrides every setter with a
 * covariant return type so fluent chains keep returning {@code AsyncExtendClientBuilder} and
 * {@link #build()} keeps returning {@link AsyncExtendClient}.</p>
 */
package ai.extend;

import ai.extend.core.Environment;
import okhttp3.OkHttpClient;

/**
 * Builder for {@link AsyncExtendClient}.
 */
public class AsyncExtendClientBuilder extends AsyncExtendClientBaseBuilder {

    /**
     * Sets the API key (convenience alias for {@link #token(String)}).
     */
    public AsyncExtendClientBuilder apiKey(String apiKey) {
        super.token(apiKey);
        return this;
    }

    /**
     * Sets a custom base URL (convenience alias for {@link #url(String)}).
     */
    public AsyncExtendClientBuilder baseUrl(String baseUrl) {
        super.url(baseUrl);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder token(String token) {
        super.token(token);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder extendApiVersion(String extendApiVersion) {
        super.extendApiVersion(extendApiVersion);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder environment(Environment environment) {
        super.environment(environment);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder url(String url) {
        super.url(url);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder timeout(int timeout) {
        super.timeout(timeout);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder maxRetries(int maxRetries) {
        super.maxRetries(maxRetries);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder httpClient(OkHttpClient httpClient) {
        super.httpClient(httpClient);
        return this;
    }

    @Override
    public AsyncExtendClientBuilder addHeader(String name, String value) {
        super.addHeader(name, value);
        return this;
    }

    @Override
    public AsyncExtendClient build() {
        return new AsyncExtendClient(buildClientOptions());
    }
}
